#include <bits/stdc++.h> 
using namespace std;

int minOperations(vector<int>& arr) {
    int operations = 0;
    int i = 0;               // left pointer
    int j = arr.size() - 1;  // right pointer

    // Keep going until pointers meet
    while(i < j) {
        if(arr[i] == arr[j]) {
            // If equal, move both pointers
            i++;
            j--;
        }
        else {
            operations++;  // need one operation

            // Always combine elements at smaller end
            if(arr[i] < arr[j]) {
                arr[i+1] = arr[i] + arr[i+1];  // combine with next element
                i++;
            }
            else {
                arr[j-1] = arr[j] + arr[j-1];  // combine with previous element
                j--;
            }
        }
    }

    return operations;
}

int main() {
    int T;
    cin >> T;

    while(T--) {
        int N;
        cin >> N;

        vector<int> arr(N);
        for(int i = 0; i < N; i++) {
            cin >> arr[i];
        }

        cout << minOperations(arr) << endl;
    }

    return 0;
}
